import { AuthProvider, useAuth } from "./context/AuthContext";
import Login from "./components/Login/Login";
import ChatRoom from "./components/Chat/ChatRoom";

/**
 * Renders Login until a user is set in AuthContext, then renders ChatRoom.
 * Kept separate from App so it can call useAuth() (must be inside the provider).
 */
function AppContent() {
  const { user } = useAuth();
  return user ? <ChatRoom /> : <Login />;
}

export default function App() {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
}
